#include<bits/stdc++.h>
using namespace std;
int fa[1000010][23],n,m,d[1000010];
char s[1000010];
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    for(int i=21;i>=0;i--)
    {
        if(d[fa[x][i]]>=d[y])
        {
            x=fa[x][i];
        }
    }
    for(int i=21;i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
int main()
{
    scanf("%s",s+1);
    n=strlen(s+1);
    int j=0;
    d[1]=1;
    for(int i=2;i<=n;i++)
    {
        while(j>0&&s[j+1]!=s[i])
        {
            j=fa[j][0];
        }
        if(s[j+1]==s[i])
        {
            j++;
        }
        fa[i][0]=j;
        d[i]=d[j]+1;
    }
    for(int i=1;i<=21;i++)
    {
        for(int j=1;j<=n;j++)
        {
            fa[j][i]=fa[fa[j][i-1]][i-1];
        }
    }
    scanf("%d",&m);
    while(m--)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        printf("%d\n",lca(x,y));
    }
    return 0;
}
